import { createCallerFactory, appRouter } from './trpc';

const createCaller = createCallerFactory(appRouter);
export const caller = createCaller({});
```
`createCallerFactory(appRouter)` returns a factory function; calling it with an empty context object produces the `caller` that can invoke procedures directly on the server.

**`src/app/page.tsx`**
```tsx
import ClientComponent from './ClientComponent';
import { caller } from '../server/caller';

export default async function Page() {
  const serverData = await caller.hello({ name: 'Server' });
  return (
    <div>
      <h1 id="server-data">{serverData}</h1>
      <ClientComponent />
    </div>
  );
}
```
The async Server Component calls `caller.hello({ name: 'Server' })` at render time and places the result (`"Hello Server"`) in `<h1 id="server-data">`.

**`src/app/ClientComponent.tsx`**
```tsx
'use client';

import { trpc } from '../utils/trpc';

export default function ClientComponent() {
  const { data } = trpc.hello.useQuery({ name: 'Client' });
  return <p id="client-data">{data}</p>;
}
```
The client component uses the tRPC React Query hook to fetch `hello({ name: 'Client' })` on the client side and renders the result (`"Hello Client"`) in `<p id="client-data">`.

